namespace sv_fdab7e5ef6a14bbaa95499a1ad9abc97.Services;

public class WarehouseInfo
{
    public required string Id { get; init; }
    public required string Name { get; init; }
}

/// <summary>
/// Scoped per-circuit so each user gets independent warehouse selection and alert state.
/// </summary>
public class WarehouseState
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new() { Id = "WH-001", Name = "Warehouse A — Downtown" },
        new() { Id = "WH-002", Name = "Warehouse B — Airport" },
        new() { Id = "WH-003", Name = "Warehouse C — Harbor" },
    ];

    public string CurrentWarehouseId { get; private set; } = AvailableWarehouses[0].Id;

    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == CurrentWarehouseId).Name;

    public int? LowStockAlertCount { get; private set; }

    public event Action? OnWarehouseChanged;
    public event Action? OnAlertCountChanged;

    public void SetWarehouse(string warehouseId)
    {
        if (CurrentWarehouseId == warehouseId) return;
        CurrentWarehouseId = warehouseId;
        LowStockAlertCount = null; // reset until new data arrives
        OnWarehouseChanged?.Invoke();
        OnAlertCountChanged?.Invoke();
    }

    public void SetLowStockAlertCount(int count)
    {
        LowStockAlertCount = count;
        OnAlertCountChanged?.Invoke();
    }
}

namespace sv_fdab7e5ef6a14bbaa95499a1ad9abc97.Services;

/// <summary>
/// Simulates a database query for low-stock items in a warehouse.
/// </summary>
public class InventoryAlertService
{
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        var count = Random.Shared.Next(0, 16);
        return Task.FromResult(count);
    }
}

@using sv_fdab7e5ef6a14bbaa95499a1ad9abc97.Services
@inject WarehouseState WarehouseState
@implements IDisposable

<div class="warehouse-selector">
    <label class="form-label mb-0 me-2 text-nowrap" for="warehouseDropdown">
        <strong>Site:</strong>
    </label>
    <select id="warehouseDropdown"
            class="form-select form-select-sm"
            value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseSelected">
        @foreach (var wh in WarehouseState.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    private void OnWarehouseSelected(ChangeEventArgs e)
    {
        var id = e.Value?.ToString();
        if (!string.IsNullOrEmpty(id))
        {
            WarehouseState.SetWarehouse(id);
        }
    }

    protected override void OnInitialized()
    {
        WarehouseState.OnWarehouseChanged += StateHasChanged;
    }

    public void Dispose()
    {
        WarehouseState.OnWarehouseChanged -= StateHasChanged;
    }
}

@using sv_fdab7e5ef6a14bbaa95499a1ad9abc97.Services
@inject WarehouseState WarehouseState
@implements IDisposable

@if (WarehouseState.LowStockAlertCount is > 0)
{
    <span class="badge bg-danger rounded-pill ms-auto">@WarehouseState.LowStockAlertCount</span>
}

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnAlertCountChanged += OnStateChanged;
    }

    private void OnStateChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        WarehouseState.OnAlertCountChanged -= OnStateChanged;
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@using sv_fdab7e5ef6a14bbaa95499a1ad9abc97.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard — @WarehouseState.CurrentWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">@WarehouseState.CurrentWarehouseName</h5>
        <p class="card-text text-muted">Warehouse ID: @WarehouseState.CurrentWarehouseId</p>
    </div>
</div>

<div class="row">
    <div class="col-md-4">
        <div class="card text-bg-@(_alertCardColor) mb-3">
            <div class="card-header">Low-Stock Alerts</div>
            <div class="card-body">
                @if (WarehouseState.LowStockAlertCount is null)
                {
                    <h2 class="card-title">
                        <span class="spinner-border spinner-border-sm" role="status"></span>
                        Checking…
                    </h2>
                }
                else
                {
                    <h2 class="card-title">@WarehouseState.LowStockAlertCount</h2>
                    <p class="card-text">items below minimum stock level</p>
                }
            </div>
            <div class="card-footer text-body-secondary">
                Refreshes every 10 seconds
            </div>
        </div>
    </div>
</div>

@code {
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;

    private string _alertCardColor => WarehouseState.LowStockAlertCount switch
    {
        null => "secondary",
        0 => "success",
        <= 5 => "warning",
        _ => "danger"
    };

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnWarehouseChanged += OnWarehouseChanged;
        await PollAlerts();
        StartPolling();
    }

    private void StartPolling()
    {
        StopPolling();
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        _ = PollLoopAsync(_cts.Token);
    }

    private void StopPolling()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
        _timer?.Dispose();
        _timer = null;
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        try
        {
            while (await _timer!.WaitForNextTickAsync(ct))
            {
                await PollAlerts();
                await InvokeAsync(StateHasChanged);
            }
        }
        catch (OperationCanceledException) { }
    }

    private async Task PollAlerts()
    {
        var count = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        WarehouseState.SetLowStockAlertCount(count);
    }

    private void OnWarehouseChanged()
    {
        // Restart polling for the new warehouse immediately
        InvokeAsync(async () =>
        {
            await PollAlerts();
            StartPolling();
            StateHasChanged();
        });
    }

    public void Dispose()
    {
        WarehouseState.OnWarehouseChanged -= OnWarehouseChanged;
        StopPolling();
    }
}

