namespace sv_fdab7e5ef6a14bbaa95499a1ad9abc97.Services;

public class WarehouseInfo
{
    public required string Id { get; init; }
    public required string Name { get; init; }
}

/// <summary>
/// Scoped per-circuit so each user gets independent warehouse selection and alert state.
/// </summary>
public class WarehouseState
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new() { Id = "WH-001", Name = "Warehouse A — Downtown" },
        new() { Id = "WH-002", Name = "Warehouse B — Airport" },
        new() { Id = "WH-003", Name = "Warehouse C — Harbor" },
    ];

    public string CurrentWarehouseId { get; private set; } = AvailableWarehouses[0].Id;

    public string CurrentWarehouseName =>
        AvailableWarehouses.First(w => w.Id == CurrentWarehouseId).Name;

    public int? LowStockAlertCount { get; private set; }

    public event Action? OnWarehouseChanged;
    public event Action? OnAlertCountChanged;

    public void SetWarehouse(string warehouseId)
    {
        if (CurrentWarehouseId == warehouseId) return;
        CurrentWarehouseId = warehouseId;
        LowStockAlertCount = null; // reset until new data arrives
        OnWarehouseChanged?.Invoke();
        OnAlertCountChanged?.Invoke();
    }

    public void SetLowStockAlertCount(int count)
    {
        LowStockAlertCount = count;
        OnAlertCountChanged?.Invoke();
    }
}

namespace sv_fdab7e5ef6a14bbaa95499a1ad9abc97.Services;

/// <summary>
/// Simulates a database query for low-stock items in a warehouse.
/// </summary>
public class InventoryAlertService
{
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        var count = Random.Shared.Next(0, 16);
        return Task.FromResult(count);
    }
}

